    private static string[] GetFixedOfficialResourceSkillCandidateCardNos()
    {
        var catalogPath = Path.Combine(ResolveRepositoryRoot(), "data", "official", "card-catalog.zh-CN.json");
        using var document = JsonDocument.Parse(File.ReadAllText(catalogPath));

        return document.RootElement.GetProperty("cards").EnumerateArray()
            .Where(card =>
            {
                var effectText = card.GetProperty("cardEffect").GetString() ?? string.Empty;
                return effectText.Contains("{{获得}}", StringComparison.Ordinal)
                    && effectText.Contains("获得费用资源的技能无法成为其他法术的反应目标", StringComparison.Ordinal);
            })
            .Select(card => card.GetProperty("cardNo").GetString()!)
            .Order(StringComparer.Ordinal)
            .ToArray();
    }

    private static int CountPost03EeMatrixRows(IReadOnlyCollection<JsonElement> functionalUnits, string matrixRowQuery)
    {
        return matrixRowQuery switch
        {
            "all-functional-units" => functionalUnits.Count,
            "payment-cost" => functionalUnits.Count(unit => HasStringArrayValue(unit, "uncoveredEffectCategories", "payment-cost")),
            "payment-or-targeting-stack-timing" => functionalUnits.Count(unit =>
                HasStringArrayValue(unit, "uncoveredEffectCategories", "payment-cost")
                    || HasStringArrayValue(unit, "uncoveredEffectCategories", "targeting-stack-timing")),
            "payment-and-targeting-stack-timing" => functionalUnits.Count(unit =>
                HasStringArrayValue(unit, "uncoveredEffectCategories", "payment-cost")
                    && HasStringArrayValue(unit, "uncoveredEffectCategories", "targeting-stack-timing")),
            _ => throw new InvalidOperationException($"Unknown 4D-03EE-E matrix row query: {matrixRowQuery}")
        };
    }

    private static int CountPost03EfMatrixRowsWithBlocker(
        IReadOnlyCollection<JsonElement> functionalUnits,
        string matrixRowQuery,
        string blocker)
    {
        return functionalUnits.Count(unit =>
            MatchesPost03EeMatrixRowQuery(unit, matrixRowQuery) && HasStage4BBlocker(unit, blocker));
    }

    private static bool MatchesPost03EeMatrixRowQuery(JsonElement functionalUnit, string matrixRowQuery)
    {
        return matrixRowQuery switch
        {
            "all-functional-units" => true,
            "payment-cost" => HasStringArrayValue(functionalUnit, "uncoveredEffectCategories", "payment-cost"),
            "payment-or-targeting-stack-timing" =>
                HasStringArrayValue(functionalUnit, "uncoveredEffectCategories", "payment-cost")
                || HasStringArrayValue(functionalUnit, "uncoveredEffectCategories", "targeting-stack-timing"),
            "payment-and-targeting-stack-timing" =>
                HasStringArrayValue(functionalUnit, "uncoveredEffectCategories", "payment-cost")
                && HasStringArrayValue(functionalUnit, "uncoveredEffectCategories", "targeting-stack-timing"),
            _ => throw new InvalidOperationException($"Unknown 4D-03EE-E matrix row query: {matrixRowQuery}")
        };
    }

    private static int CountPost03EpPaymentCostRowsByStage4BFreezeStatus(
        IReadOnlyCollection<JsonElement> functionalUnits,
        string freezeStatus)
    {
        return functionalUnits.Count(unit =>
            MatchesPost03EeMatrixRowQuery(unit, "payment-cost")
            && unit.TryGetProperty("stage4B", out var stage4B)
            && stage4B.TryGetProperty("freezeStatus", out var actualFreezeStatus)
            && string.Equals(actualFreezeStatus.GetString(), freezeStatus, StringComparison.Ordinal));
    }

    private static bool HasStage4BBlocker(JsonElement functionalUnit, string blocker)
    {
        return functionalUnit.TryGetProperty("stage4B", out var stage4B)
            && HasStringArrayValue(stage4B, "fullOfficialBlockers", blocker);
    }

    private static bool HasStringArrayValue(JsonElement element, string propertyName, string expected)
    {
        if (!element.TryGetProperty(propertyName, out var values) || values.ValueKind != JsonValueKind.Array)
        {
            return false;
        }

        return values
            .EnumerateArray()
            .Any(value => string.Equals(value.GetString(), expected, StringComparison.Ordinal));
    }

    private static string ResolveRepositoryRoot()
    {
        var current = new DirectoryInfo(Directory.GetCurrentDirectory());
        while (current is not null)
        {
            if (File.Exists(Path.Combine(current.FullName, "Riftbound.slnx")))
            {
                return current.FullName;
            }

            current = current.Parent;
        }

        throw new InvalidOperationException("Could not locate repository root containing Riftbound.slnx.");
    }

    private static string ExtractSection(string text, string startMarker, string endMarker)
    {
        var start = text.IndexOf(startMarker, StringComparison.Ordinal);
        Assert.True(start >= 0, $"Missing section start marker: {startMarker}");

        var end = text.IndexOf(endMarker, start + startMarker.Length, StringComparison.Ordinal);
        Assert.True(end > start, $"Missing section end marker: {endMarker}");

        return text[start..end];
    }

